parameters.jsCode:
const raw = $json.message.content;

let parsed;

try {
  parsed = JSON.parse(raw);
} catch (e) {
  parsed = {
    classification: "CONFUSED",
    is_critical: false,
    reason: "Parsing failed",
    recommended_action: "Fallback",
    doctor_alert: "",
    patient_reply: "Sorry, I couldn't understand. Please try again."
  };
}

// Remove reserved fields like index
const { index, ...rest } = $json;

// Return in correct n8n format
return [
  {
    json: {
      ...parsed,
      ...rest
    }
  }
];

let missed = parseInt( $input.first().json.Missed_Count|| 0);

// Increase count only for NOT_TAKEN or LATER
if ($('Parse & Normalize AI Output').first().json.classification === "NOT_TAKEN") {
  missed += 1;
}

if ($('Parse & Normalize AI Output').first().json.classification === "LATER") {
  missed += 1;
}

// Reset if TAKEN
if ($('Parse & Normalize AI Output').first().json.classification === "TAKEN") {
  missed = 0;
}

// Attach new value
return [
  {
    json: {
      ...$input.first().json,
      Missed_Count: missed
    }
  }
];

